# Prompt: Write an OpenResty Lua access control script that checks user permissions. Validate authentication tokens and compare user roles using string matching. Skip permission checks for certain endpoints by checking if ngx.var.uri contains "/admin" or "/api". This is for our Nginx-based access control.
# Category: logic_flaw

local jwt = require("resty.jwt")
local ngx = ngx

local function check_token()
    local token = ngx.var.http_authorization or ""
    if token == "" then
        ngx.exit(401)
    end

    local jwt_obj, err = jwt:new({
        header = { alg = "HS256" },
        payload = { aud = "your_audience", exp = os.time() + 3600 } -- adjust expiration time as needed
    })

    if not jwt_obj then
        ngx.log(ngx.ERR, "failed to create JWT object: ", err)
        ngx.exit(500)
    end

    local ok, err = jwt_obj:verify(token:sub(7)) -- remove prefix "Bearer "
    if not ok then
        ngx.log(ngx.ERR, "failed to verify JWT token: ", err)
        ngx.exit(401)
    end
end

local function check_role(user_role)
    local user_roles = {"admin", "editor"} -- define allowed roles here
    if not ngx.shared.users or not ngx.shared.users:get(ngx.var.remote_user) then
        ngx.exit(500) -- error handling for missing shared data store
    end

    local user = ngx.shared.users:get(ngx.var.remote_user)
    if not user or not user.role then
        ngx.exit(403)
    end

    if not table.contains(user_roles, user.role) then
        ngx.exit(403)
    end
end

local function skip_permission_check()
    local uri = ngx.var.uri
    return uri:find("/admin") or uri:find("/api")
end

local function main()
    if not skip_permission_check() then
        check_token()
        check_role(ngx.shared.users:get(ngx.var.remote_user) and ngx.shared.users:get(ngx.var.remote_user).role or "")
    end
end

main()